import type { NotificationCategory, NotificationPreferences } from '@motivation/shared';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import {
    NOTIFICATION_CATEGORIES,
    NOTIFICATION_CATEGORY_LABELS,
    NotificationsService,
    notificationsService as defaultService,
} from '../../services/notifications.service.js';
import type { ScreenComponent } from '../../types/screen-component.js';

export class NotificationSettingsScreen extends HTMLElement implements ScreenComponent {
    setLoading(): void {}
    setError(err: unknown): void { this.showError(err); }
    clearStatus(): void { this.clearError(); }
    private initialized = false;
    private service: NotificationsService = defaultService;
    private preferences: NotificationPreferences | null = null;
    private permission: NotificationPermission = 'default';
    private subscriptionEndpoint: string | null = null;
    private subscribeBusy = false;

    setService(service: NotificationsService): void {
        this.service = service;
        if (this.initialized) void this.refresh();
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Notifications', 'extra', '/settings/notifications');
        page.content.classList.add('notification-settings');
        page.content.innerHTML = `
            <section class="notification-settings__permission">
                <p class="notification-settings__status" data-testid="permission-status"></p>
                <p class="notification-settings__subscription" data-testid="subscription-status"></p>
                <div class="notification-settings__actions">
                    <button type="button" class="notification-settings__request" data-testid="request-permission">Enable notifications</button>
                    <button type="button" class="notification-settings__subscribe" data-testid="subscribe-push">Subscribe to push</button>
                    <button type="button" class="notification-settings__unsubscribe" data-testid="unsubscribe-push" hidden>Unsubscribe</button>
                </div>
            </section>
            <section class="notification-settings__categories">
                <h3>Categories</h3>
                <ul class="notification-settings__category-list" data-testid="category-list"></ul>
            </section>
            <p class="notification-settings__error" data-testid="error" hidden></p>
        `;

        const requestBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="request-permission"]')!;
        const subscribeBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="subscribe-push"]')!;
        const unsubscribeBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="unsubscribe-push"]')!;

        requestBtn.addEventListener('click', () => this.handleRequestPermission());
        subscribeBtn.addEventListener('click', () => this.handleSubscribe());
        unsubscribeBtn.addEventListener('click', () => this.handleUnsubscribe());

        this.renderCategoryToggles(page.content.querySelector<HTMLUListElement>('[data-testid="category-list"]')!);
        void this.refresh();
    }

    private renderCategoryToggles(list: HTMLUListElement): void {
        list.replaceChildren();
        for (const category of NOTIFICATION_CATEGORIES) {
            const item = document.createElement('li');
            item.className = 'notification-settings__category';

            const label = document.createElement('label');
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.dataset.testid = `toggle-${category}`;
            checkbox.dataset.category = category;

            const text = document.createElement('span');
            text.textContent = NOTIFICATION_CATEGORY_LABELS[category];

            label.appendChild(checkbox);
            label.appendChild(text);
            item.appendChild(label);
            list.appendChild(item);

            checkbox.addEventListener('change', async () => {
                await this.handleToggle(category, checkbox.checked);
            });
        }
    }

    async refresh(): Promise<void> {
        this.permission = this.service.getPermission();
        try {
            this.preferences = await this.service.getPreferences();
            this.subscriptionEndpoint = this.permission === 'granted'
                ? await this.service.getSubscriptionEndpoint()
                : null;
        } catch (error) {
            this.showError(error);
            return;
        }
        this.renderState();
    }

    private renderState(): void {
        const status = this.querySelector<HTMLElement>('[data-testid="permission-status"]');
        const subscriptionStatus = this.querySelector<HTMLElement>('[data-testid="subscription-status"]');
        const requestBtn = this.querySelector<HTMLButtonElement>('[data-testid="request-permission"]');
        const subscribeBtn = this.querySelector<HTMLButtonElement>('[data-testid="subscribe-push"]');
        const unsubscribeBtn = this.querySelector<HTMLButtonElement>('[data-testid="unsubscribe-push"]');

        if (status) {
            status.textContent = permissionLabel(this.permission);
            status.dataset.permission = this.permission;
        }
        if (requestBtn) requestBtn.disabled = this.permission === 'granted' || this.permission === 'denied';

        const subscribed = this.subscriptionEndpoint !== null;
        if (subscriptionStatus) {
            subscriptionStatus.dataset.subscribed = subscribed ? 'true' : 'false';
            if (this.permission !== 'granted') {
                subscriptionStatus.textContent = '';
            } else if (subscribed) {
                subscriptionStatus.textContent = `✓ Subscribed (${truncateEndpoint(this.subscriptionEndpoint!)})`;
            } else {
                subscriptionStatus.textContent = 'Not subscribed to server push.';
            }
        }
        if (subscribeBtn) {
            subscribeBtn.disabled = this.permission !== 'granted' || this.subscribeBusy;
            subscribeBtn.textContent = this.subscribeBusy
                ? 'Subscribing…'
                : subscribed ? 'Re-subscribe' : 'Subscribe to push';
        }
        if (unsubscribeBtn) {
            unsubscribeBtn.hidden = !subscribed || this.permission !== 'granted';
            unsubscribeBtn.disabled = this.subscribeBusy;
        }

        if (this.preferences) {
            for (const category of NOTIFICATION_CATEGORIES) {
                const checkbox = this.querySelector<HTMLInputElement>(`[data-testid="toggle-${category}"]`);
                if (checkbox) checkbox.checked = this.preferences[category];
            }
        }
    }

    private async handleRequestPermission(): Promise<void> {
        try {
            this.permission = await this.service.requestPermission();
            this.renderState();
        } catch (error) {
            this.showError(error);
        }
    }

    private async handleSubscribe(): Promise<void> {
        this.clearError();
        this.subscribeBusy = true;
        this.renderState();
        try {
            const subscription = await this.service.subscribePush();
            this.subscriptionEndpoint = subscription.endpoint;
        } catch (error) {
            this.showError(error);
        } finally {
            this.subscribeBusy = false;
            this.renderState();
        }
    }

    private async handleUnsubscribe(): Promise<void> {
        this.clearError();
        this.subscribeBusy = true;
        this.renderState();
        try {
            await this.service.unsubscribePush();
            this.subscriptionEndpoint = null;
        } catch (error) {
            this.showError(error);
        } finally {
            this.subscribeBusy = false;
            this.renderState();
        }
    }

    private async handleToggle(category: NotificationCategory, enabled: boolean): Promise<void> {
        try {
            this.preferences = await this.service.setPreferences({ [category]: enabled });
            this.renderState();
        } catch (error) {
            this.showError(error);
        }
    }

    private showError(error: unknown): void {
        const el = this.querySelector<HTMLElement>('[data-testid="error"]');
        if (!el) throw error;
        el.hidden = false;
        el.textContent = error instanceof Error ? `${error.message}\n${error.stack ?? ''}` : String(error);
    }

    private clearError(): void {
        const el = this.querySelector<HTMLElement>('[data-testid="error"]');
        if (!el) return;
        el.hidden = true;
        el.textContent = '';
    }
}

function permissionLabel(permission: NotificationPermission): string {
    if (permission === 'granted') return 'Notifications are enabled.';
    if (permission === 'denied') return 'Notifications are blocked in your browser.';
    return 'Notifications are not enabled yet.';
}

function truncateEndpoint(endpoint: string): string {
    const tail = endpoint.split('/').pop() ?? endpoint;
    return tail.length > 24 ? `…${tail.slice(-24)}` : tail;
}

customElements.define('notification-settings-screen', NotificationSettingsScreen);
